class Solution {
public:
    bool check(TreeNode *p, TreeNode *q) {
        if (!p && !q) return true;
        if (!p || !q) return false;
        return p->val == q->val && check(p->left, q->right) && check(p->right, q->left); // 镜像：左对右、右对左交叉比较
    }

    bool isSymmetric(TreeNode* root) {
        return check(root->left, root->right);
    }
};
